import type { ButtonTone, ButtonVariant } from "@/components/control-ui/contracts";
import type { ControlUiSkin } from "@/components/control-ui/skin";

/*
 * ADVANCED skin: tokens (theme.css) + body type rendering & Tabs knobs (skin.css) + these per-slot
 * classes. The Linear through-line: hairlines carry structure, indigo carries intent, and only
 * floating surfaces are allowed elevation. Filled + bordered actions are pills; every other control
 * keeps the 6px control corner. No "use client" — the config stays RSC-pure.
 */

// Brand focus: the ring token IS the indigo, offset from the surface behind it.
const focus = "focus-visible:ring-2 focus-visible:ring-[var(--ring)] focus-visible:ring-offset-2 focus-visible:ring-offset-background";
// Linear controls change color, never size — `active:scale-100` evicts the recipe's press-shrink.
// shadow-(--x) not shadow-[var(--x)]: tailwind-merge reads the bracket form as a shadow COLOR and would keep the recipe's box-shadow beside it.
const controlMotion =
  "transition-[background-color,border-color,box-shadow,color] duration-[var(--duration-fast)] ease-[var(--ease-standard)] active:scale-100";

// The pill: filled and bordered ACTIONS only (dialog footers, submit, CTAs).
const solid = `rounded-full bg-[var(--primary)] text-[var(--primary-foreground)] shadow-(--linear-control-shadow) hover:bg-[var(--linear-primary-hover)] active:bg-[var(--linear-primary-active)] ${controlMotion} ${focus}`;
const danger = `rounded-full bg-[var(--destructive)] text-[var(--destructive-foreground)] shadow-(--linear-control-shadow) hover:brightness-105 active:brightness-95 ${controlMotion} ${focus}`;
// `surface` keeps the recipe's inset ring (and its data-[active] brand tint); only the fill is re-painted.
const surfaceControl = `rounded-full bg-[var(--linear-control-bg)] shadow-(--linear-control-shadow) hover:bg-[var(--linear-control-hover)] active:bg-[var(--linear-control-active)] ${controlMotion} ${focus}`;
// Icon buttons, toolbar chrome, menu triggers: 6px corner, row-fill hover, no ring and no elevation.
// `ring-0`/`bg-transparent` matter on the shared control chrome (menu + select triggers), not on Button's own ghost variant.
const ghost = `rounded-[var(--radius-control)] bg-transparent shadow-none ring-0 hover:bg-[var(--linear-row-hover)] ${controlMotion} ${focus}`;
const quiet = `${ghost} text-muted-foreground hover:text-foreground data-[active=true]:bg-[var(--linear-row-active)] data-[active=true]:text-foreground`;

function button(variant: ButtonVariant, tone: ButtonTone) {
  if (tone === "danger") return danger;
  if (variant === "solid") return solid;
  if (variant === "surface") return surfaceControl;
  if (variant === "ghost") return ghost;
  return quiet;
}

// Fields are outlines, not fills: transparent body, --input hairline, brand border once focused.
const field =
  "rounded-[var(--radius-control)] border-[var(--input)] bg-transparent shadow-none transition-[border-color,box-shadow] duration-[var(--duration-fast)] focus-visible:border-[var(--primary)] focus-visible:ring-2 focus-visible:ring-[var(--ring)]/25";
// Select/menu triggers wear the same outline, but their recipe draws the edge with an inset ring, not a border.
const ringField = `rounded-[var(--radius-control)] bg-transparent shadow-none ring-1 ring-inset ring-[var(--input)] hover:bg-[var(--linear-row-hover)] ${controlMotion} ${focus}`;

// Floating surfaces: the one place elevation is spent. Concentric geometry stays the recipe's.
const popup = "border-border bg-popover shadow-(--linear-menu-shadow)";
const row =
  "rounded-[var(--radius-popup-item)] px-2 py-1 text-label data-[highlighted]:bg-[var(--linear-row-hover)] data-[disabled]:opacity-40";
const menuLabel = "px-2 py-1 text-caption font-medium normal-case tracking-normal text-muted-foreground";
const separator = "mx-0 my-1 bg-border";
// Modals float hardest and drop their edge in light mode (the shadow IS the boundary); dark keeps a rim.
const modal = "rounded-[var(--radius-panel)] border-transparent bg-popover shadow-(--linear-modal-shadow) dark:border-border";

// Panels are held by a hairline, never by a lift. Recipes draw their edge with either `border` or an
// inset ring, so these only re-color the ring and flatten the shadow — the widths stay the recipe's.
const panel = "rounded-[var(--radius-panel)] bg-card shadow-none ring-border";
const panelHeader = "border-b border-border bg-transparent";
// The one 1px lift in the shell: enough to detach the white sheet from the canvas.
const sheet = "rounded-[var(--radius-panel)] border-border bg-card shadow-(--linear-panel-shadow)";

// Nav rows and tree rows share ONE chrome. Every background sits on a modifier chain that
// SELECTION_INDICATOR_BG_RESET restates, so an app opting into indicator="slide" evicts them cleanly.
const navRow =
  "rounded-[var(--radius-control)] font-medium text-muted-foreground hover:bg-[var(--linear-row-hover)] hover:text-foreground active:bg-[var(--linear-row-active)] data-[active=true]:bg-[var(--linear-row-active)] data-[active=true]:text-foreground data-[state=open]:hover:bg-[var(--linear-row-active)]";
const treeRow =
  "rounded-[var(--radius-control)] text-muted-foreground hover:bg-[var(--linear-row-hover)] hover:text-foreground data-[selected]:bg-[var(--linear-row-active)] data-[selected]:font-medium data-[selected]:text-foreground";

export const skin: ControlUiSkin = {
  id: "linear",
  // Linear's rail is narrower than shadcn's 16rem default and never draws a surface of its own.
  sidebarWidth: "15rem",
  slots: {
    button: {
      root: ({ variant, tone }) => button(variant, tone),
      content: "gap-1.5",
    },
    select: {
      content: popup,
      trigger: ringField,
      item: row,
    },
    menu: {
      trigger: ghost,
      content: popup,
      item: row,
      separator: separator,
      label: menuLabel,
    },
    menubar: {
      trigger: ghost,
      content: popup,
      "sub-content": popup,
      item: row,
      separator: separator,
      label: menuLabel,
    },
    combobox: {
      trigger: ghost,
      input: field,
      content: popup,
      item: row,
    },
    input: {
      root: field,
    },
    "input-group": {
      root: field,
    },
    textarea: {
      root: field,
    },
    "native-select": {
      root: field,
    },
    autocomplete: {
      input: field,
      content: popup,
      item: row,
    },
    "number-field": {
      group: field,
    },
    "input-otp": {
      slot: field,
    },
    checkbox: {
      root: "rounded-[max(3px,calc(var(--radius-control)*0.5))] border-[var(--input)]",
    },
    "radio-group": {
      item: "border-[var(--input)]",
    },
    slider: {
      thumb: "rounded-full border-border bg-card shadow-(--linear-control-shadow)",
      indicator: "bg-[var(--primary)]",
    },
    progress: {
      indicator: "bg-[var(--primary)]",
    },
    meter: {
      indicator: "bg-[var(--primary)]",
    },
    "context-menu": {
      content: popup,
      "sub-content": popup,
      item: row,
      "checkbox-item": row,
      "radio-item": row,
      "sub-trigger": `${row} data-[popup-open]:bg-[var(--linear-row-hover)]`,
      separator: separator,
      label: menuLabel,
      shortcut: "ml-auto text-caption tracking-normal text-muted-foreground",
    },
    "navigation-menu": {
      viewport: popup,
    },
    popover: {
      content: popup,
    },
    "hover-card": {
      content: popup,
    },
    "thread-rail": {
      popover: popup,
      item: "rounded-full bg-[var(--linear-row-active)]",
    },
    "trigger-menu": {
      root: popup,
      item: row,
      "group-label": menuLabel,
    },
    toast: {
      root: popup,
    },
    command: {
      root: `${popup} overflow-hidden`,
      "input-wrapper": "border-b border-border",
      item: `${row} data-[selected=true]:bg-[var(--linear-row-hover)]`,
      shortcut: "ml-auto text-caption text-muted-foreground",
    },
    dialog: {
      content: modal,
      title: "text-body-lg font-semibold tracking-[-0.01em]",
      description: "text-body text-muted-foreground",
    },
    "alert-dialog": {
      content: modal,
      title: "text-body-lg font-semibold tracking-[-0.01em]",
      description: "text-body text-muted-foreground",
    },
    sheet: {
      content: "border-border bg-popover shadow-(--linear-modal-shadow)",
    },
    sidebar: {
      inner: "border-0 bg-transparent",
      "menu-button": navRow,
      "group-label": "px-2 text-caption font-medium text-muted-foreground",
    },
    "sidebar-layout": {
      content: sheet,
    },
    tree: {
      root: "text-label",
      "item-trigger": treeRow,
    },
    tabs: {
      tab: "font-medium",
    },
    "table-of-contents": {
      item: "text-label",
    },
    card: {
      root: "rounded-[var(--radius-panel)] bg-card shadow-none",
    },
    alert: {
      root: "rounded-[var(--radius-panel)] bg-card shadow-none",
    },
    item: {
      root: `rounded-[var(--radius-control)] hover:bg-[var(--linear-row-hover)] ${controlMotion}`,
    },
    empty: {
      root: "rounded-[var(--radius-panel)] border border-dashed border-border bg-transparent",
    },
    badge: {
      root: "rounded-full font-medium",
    },
    kbd: {
      root: "rounded-[calc(var(--radius-control)*0.67)] bg-transparent text-muted-foreground shadow-none ring-border",
    },
    "scroll-area": {
      thumb: "rounded-full bg-foreground/20",
    },
    "chat-scene": {
      root: "rounded-[var(--radius-scene)] border-border bg-card shadow-(--linear-panel-shadow)",
    },
    activity: {
      root: ({ kind }) => (kind === "tool" ? "rounded-[var(--radius-panel)] bg-card shadow-none" : undefined),
      trigger: ({ kind }) => (kind === "tool" ? "rounded-[var(--radius-panel)]" : undefined),
    },
    "chat-message": {
      content: ({ role }) =>
        role === "user"
          ? "rounded-[var(--radius-field)] bg-[var(--primary)] text-[var(--primary-foreground)] shadow-none"
          : "rounded-[var(--radius-field)] bg-transparent",
      avatar: "rounded-full border-border bg-[var(--linear-control-bg)]",
    },
    "chat-input": {
      shell: "rounded-[var(--radius-field)] border-border bg-card shadow-(--linear-panel-shadow) ring-0",
      submit: solid,
      mention: "rounded-[var(--radius-control)] border-border bg-[var(--linear-row-hover)]",
    },
    "markdown-block": {
      root: "rounded-[var(--radius-panel)] bg-card shadow-none ring-0",
      header: panelHeader,
    },
    code: {
      root: panel,
      header: panelHeader,
      title: "font-mono text-caption text-muted-foreground",
    },
    "code-diff": {
      root: panel,
      header: panelHeader,
    },
    "inline-attachment": {
      root: panel,
      image: "rounded-[var(--radius-control)]",
    },
  },
};

/*
 * The pack's own vars + the three things Tailwind classes cannot say: body-inherited type rendering,
 * and the Tabs component-local knobs. Everything else lives in skin.config (slots) or theme.css (tokens).
 * All scoped [data-skin="linear"] so several packs co-compile in one build.
 */

/* Pack vars — NOT theme-contract names. Row fills derive from --foreground, so one declaration
 * serves both modes (the token flips, the alpha recipe doesn't). Surfaces/shadows are mode-dependent. */
[data-skin="linear"] {
  --linear-row-hover: oklch(from var(--foreground) l c h / 0.05);
  --linear-row-active: oklch(from var(--foreground) l c h / 0.08);
  --linear-control-bg: var(--card);
  --linear-control-hover: oklch(from var(--foreground) l c h / 0.04);
  --linear-control-active: oklch(from var(--foreground) l c h / 0.07);

  /* The brand ramp: Linear darkens the indigo on press rather than fading it. */
  --linear-primary-hover: oklch(0.5897 0.1527 276.397); /* #6771d6 */
  --linear-primary-active: oklch(0.5177 0.1507 275.398); /* #525cbd */

  /* Elevation, spelled out: the sheet and its cards are held by hairlines; popups and modals lift.
   * Own vars (not `shadow-(--shadow-pop)`) so the tiers stay legible and tunable per surface class. */
  --linear-control-shadow: 0 1px 1px 0 oklch(from var(--shadow-color) l c h / 0.05);
  --linear-panel-shadow: 0 1px 3px 0 oklch(from var(--shadow-color) l c h / 0.04);
  --linear-menu-shadow:
    0 1px 2px 0 oklch(from var(--shadow-color) l c h / 0.08),
    0 6px 24px -4px oklch(from var(--shadow-color) l c h / 0.14);
  --linear-modal-shadow:
    0 4px 12px 0 oklch(from var(--shadow-color) l c h / 0.1),
    0 20px 70px -10px oklch(from var(--shadow-color) l c h / 0.22);

  --linear-tab-active-bg: var(--card);
  --linear-tab-active-shadow:
    0 0 0 1px var(--border),
    0 1px 2px 0 oklch(from var(--shadow-color) l c h / 0.06);
}

/* Dark: raised surfaces get lighter, not brighter-edged; shadows go deep and neutral. */
:where(.dark) [data-skin="linear"],
.dark[data-skin="linear"] {
  --linear-control-bg: oklch(1 0 0 / 0.05);
  --linear-control-hover: oklch(1 0 0 / 0.09);
  --linear-control-active: oklch(1 0 0 / 0.12);
  --linear-control-shadow: 0 1px 1px 0 oklch(0 0 0 / 0.3);
  --linear-panel-shadow: 0 1px 2px 0 oklch(0 0 0 / 0.25);
  --linear-menu-shadow:
    0 0 0 1px oklch(1 0 0 / 0.04),
    0 8px 32px -4px oklch(0 0 0 / 0.6);
  --linear-modal-shadow:
    0 0 0 1px oklch(1 0 0 / 0.05),
    0 24px 80px -12px oklch(0 0 0 / 0.7);
  --linear-tab-active-bg: oklch(1 0 0 / 0.07);
  --linear-tab-active-shadow: none;
}

/* Type rendering is inherited, not a utility: Linear ships Inter with its character variants on and
 * a hair of negative tracking across the whole app. Scoped to the skinned document, body-level so
 * portalled popups inherit it too. */
:root[data-skin="linear"] body {
  -webkit-font-smoothing: antialiased;
  -moz-osx-font-smoothing: grayscale;
  letter-spacing: -0.0075em;
  font-feature-settings:
    "cv01" 1,
    "cv02" 1,
    "cv03" 1,
    "cv04" 1,
    "calt" 1,
    "liga" 1;
}

@layer components {
  /* Sliding selection pill (apps opting into indicator="slide", the docs shell among them): Linear's
   * selected row is a flat ink wash, never a raised card. Re-values of the library's own knobs. */
  [data-skin="linear"] :where([data-control-ui="track-highlight"][data-slot="root"]) {
    --track-highlight-bg: var(--linear-row-active);
    --track-highlight-ring: transparent;
    --track-highlight-shadow: none;
  }

  /* Tabs: no recessed well. The track is bare, the active chip is a raised card — re-values of the
   * library's component-local knobs, so geometry, states and the `line` variant stay baseline's. */
  [data-skin="linear"] :where([data-control-ui="tabs"][data-slot="list"]) {
    --tabs-trigger-radius: var(--radius-control);
    --tabs-list-padding: 0rem;
    --tabs-list-gap: 0.25rem;
    --tabs-list-bg: transparent;
    --tabs-indicator-bg: var(--linear-tab-active-bg);
    --tabs-indicator-shadow: var(--linear-tab-active-shadow);
    --tabs-indicator-ease: var(--ease-standard);
    --tabs-trigger-font-size: var(--text-label);
    --tabs-trigger-focus-shadow: 0 0 0 2px oklch(from var(--ring) l c h / 0.45);
    --tabs-line-border-color: var(--border);
    --tabs-line-indicator-bg: var(--primary);
  }
}

/*
 * ADVANCED skin (tokens + skin.css material + skin.config slots) — a reading of Linear's product UI:
 * indigo brand on a near-neutral cool ramp, 13px chrome, 4px radius knob, hairline borders instead of
 * elevation, and floating surfaces that are the ONLY things allowed a real shadow.
 * Scoped under [data-skin="linear"] and complete in both modes; shared @theme bindings remain in core.
 */

[data-skin="linear"] {
  /* Inter, self-hosted by the app shell (next/font fills --font-inter); host without it falls to the system stack. */
  --font-sans: var(--font-inter, "Inter"), "Inter Variable", ui-sans-serif, system-ui, -apple-system, "Segoe UI", sans-serif;
  --font-mono: "Berkeley Mono", ui-monospace, SFMono-Regular, "SF Mono", Menlo, monospace;

  /* Type scale: Linear runs one flat 13px band for ALL chrome (nav rows, controls, body) and reserves
     the larger rungs for content headings. Label == body on purpose. */
  --text-micro: 0.625rem; /* 10px */
  --text-caption: 0.6875rem; /* 11px */
  --text-label: 0.8125rem; /* 13px — sm controls, nav rows, tooltips */
  --text-body: 0.8125rem; /* 13px — THE workhorse */
  --text-body-lg: 0.9375rem; /* 15px */
  --text-meta: 0.6875rem; /* 11px — label pills */

  /* Headings stay tight and semibold; no 700 anywhere (Linear tops out at semibold). */
  --text-heading-4: 0.875rem;
  --text-heading-4--line-height: 1.4;
  --text-heading-4--font-weight: 600;
  --text-heading-3: 1rem;
  --text-heading-3--line-height: 1.4;
  --text-heading-3--font-weight: 600;
  --text-heading-2: 1.1875rem;
  --text-heading-2--line-height: 1.3;
  --text-heading-2--font-weight: 600;
  --text-heading-1: 1.5rem; /* 24px — the issue-title rung */
  --text-heading-1--line-height: 1.25;
  --text-heading-1--font-weight: 600;
  --text-heading-1--letter-spacing: -0.014em;
  --text-display: 2rem;
  --text-display--line-height: 1.15;
  --text-display--font-weight: 600;
  --text-display--letter-spacing: -0.022em;
  --text-title-sm: 0.875rem;
  --text-title-sm--line-height: 1.4;
  --text-title-sm--font-weight: 600;
  --text-title-md: 1rem;
  --text-title-md--line-height: 1.4;
  --text-title-md--font-weight: 600;
  --text-title-lg: 1.1875rem;
  --text-title-lg--line-height: 1.3;
  --text-title-lg--font-weight: 600;

  /* Light: pure-white surfaces on a cool gray paper. card == background so the shell's content frame
     reads as the one white sheet Linear floats its whole app on. */
  --background: oklch(1 0 0);
  --foreground: oklch(0.2228 0.0079 274.573); /* #1a1b1f */
  --card: oklch(1 0 0);
  --card-foreground: oklch(0.2228 0.0079 274.573);
  --popover: oklch(1 0 0);
  --popover-foreground: oklch(0.2228 0.0079 274.573);
  --primary: oklch(0.5674 0.1585 275.206); /* #5e6ad2 — THE Linear indigo */
  --primary-foreground: oklch(1 0 0);
  --primary-text: oklch(from var(--primary) 0.48 c h);
  --muted: oklch(0.9614 0.0013 286.375); /* #f2f2f3 */
  --muted-foreground: oklch(0.5401 0.0124 280.281); /* #6d6e76 */
  --secondary: oklch(0.9614 0.0013 286.375);
  --secondary-foreground: oklch(0.2228 0.0079 274.573);
  --accent: oklch(0.9434 0.0013 286.374); /* #ececed — hover / selection fill */
  --accent-foreground: oklch(0.2228 0.0079 274.573);
  --destructive: oklch(0.576 0.1835 23.679);
  --destructive-foreground: oklch(1 0 0);
  --destructive-text: oklch(from var(--destructive) 0.48 c h);
  --ring-opacity: 1;
  --border: oklch(0.9255 0.0027 286.347 / var(--ring-opacity)); /* #e6e6e8 hairline */
  --input: oklch(0.9042 0.0027 286.346); /* #dfdfe1 — fields carry a touch more edge */
  --ring: oklch(0.5674 0.1585 275.206); /* focus == brand */
  --canvas: oklch(0.9734 0.0013 286.375); /* #f6f6f7 — the paper the white sheet sits on */

  /* Popup rows: a whisper of ink, no brand tint (Linear highlights rows, it doesn't color them).
     Derived from --foreground so the dark block inherits the same recipe with no restatement. */
  --popup-item-foreground: var(--foreground);
  --popup-item-highlight-background: oklch(from var(--foreground) l c h / 0.05);
  --popup-item-disabled-opacity: 0.4;

  /* Surfaces are opaque: no glass anywhere. The modal scrim is the only dim. */
  --popover-opacity: 1;
  --backdrop-blur-popover: 0px;
  --overlay-opacity: 0.3;
  --backdrop-blur-overlay: 0px;
  --scroll-fade-size: 1.5rem;

  /* Elevation is EARNED here: controls and panels are held by hairlines, only floating surfaces lift.
     Hence a near-zero control tier, a 1x panel tier, and popover/modal tiers pushed way up. */
  --shadow-color: oklch(0.2217 0.0084 264.39);
  --shadow-highlight: oklch(1 0 0 / 0.08); /* matte: a whisper of top light, not a lit-paper rim */
  --shadow-size: 1;
  --shadow-opacity: 0.75;
  --shadow-y: 1;
  --shadow-control-multiplier: 0.6;
  --shadow-panel-multiplier: 1;
  --shadow-popover-multiplier: 5;
  --shadow-modal-multiplier: 8;
  --shadow-ambient-multiplier: 8;

  /* THE radius knob: 4px. Controls ride 1.5x (6px), panels 3x (12px) — small, never pill-shaped by
     token (the button pill is a deliberate slot choice, not a radius side effect). */
  --radius: 0.25rem;
  --radius-control: calc(var(--radius) * 1.5);
  --radius-field: calc(var(--radius) * 2); /* 8px — composer shell, user bubble */
  --radius-panel: calc(var(--radius) * 3); /* 12px — dialogs, code, the content sheet */
  --radius-scene: calc(var(--radius) * 3.5); /* 14px */
  --corner-shape: round;
  --corner-shape-control: var(--corner-shape);
  --corner-shape-popover: var(--corner-shape);
  --corner-shape-panel: var(--corner-shape);

  /* Concentric floating-list geometry is authored here so the pack owns the exact 4px-derived ratios. */
  --popover-padding: 0.25rem;
  /* Rows carry the SAME 6px corner as controls (Linear has one row corner everywhere: menus, nav,
     tree, and the sliding selection pill, which the library shapes from this token). */
  --radius-popup-item: var(--radius-control);
  --nest-safe: 1px;
  --nest-corner-ratio: 3.41421356;
  --radius-popup-item-fit: min(var(--radius-popup-item), calc(var(--control-h-xs) / 2));
  --radius-popover: calc(var(--radius-popup-item-fit) + clamp(0px, var(--radius-popup-item-fit) * 1000, var(--popover-padding) - 1px));

  --padding-x: 0.75rem;
  --padding-y: 0.5rem;

  /* Control ramp: 32px base, so `sm` lands on Linear's 28px button. */
  --control-h: 2rem;
  --control-h-xs: round(var(--control-h) * 0.78, 1px);
  --control-h-sm: round(var(--control-h) * 0.89, 1px);
  --control-h-md: var(--control-h);
  --control-h-lg: round(var(--control-h) * 1.11, 1px);

  /* Motion is a snap, not a glide — Linear's whole feel rests on this. */
  --ease-standard: cubic-bezier(0.4, 0, 0.2, 1);
  --ease-emphasized: cubic-bezier(0.16, 1, 0.3, 1);
  --duration-fast: 90ms;
  --duration-base: 130ms;
  --duration-slow: 200ms;

  --popup-item-icon-foreground: currentColor;
  --badge-neutral: oklch(from var(--foreground) l c h / 0.08);
  --badge-neutral-foreground: var(--foreground);
  --badge-neutral-border: oklch(from var(--foreground) l c h / 0.1);
  --badge-neutral-hover: oklch(from var(--foreground) l c h / 0.12);
  --badge-slate: oklch(from var(--color-slate-500) l c h / 0.14);
  --badge-slate-foreground: var(--color-slate-800);
